function normalize(text: string) {
  return text.toLowerCase().replace(/[^a-z0-9]+/g, " ").trim();
}

function pageName() {
  return document.querySelector("h1")?.textContent?.replace(/\s+/g, " ").trim() || "Calculator";
}

function titleFromPath(path: string) {
  if (PATH_TITLES[path]) return PATH_TITLES[path];
  return path
    .replace(/^\//, "")
    .split("-")
    .map((word) => {
      const upper: Record<string, string> = { bmi: "BMI", bmr: "BMR", tdee: "TDEE", gfr: "GFR", bac: "BAC", gpa: "GPA", gcf: "GCF", lcm: "LCM", ira: "IRA", roi: "ROI", apr: "APR", btu: "BTU", gdp: "GDP", url: "URL" };
      return upper[word] || word.charAt(0).toUpperCase() + word.slice(1);
    })
    .join(" ");
}

function sendTo(targetPath: string): ChainSuggestion {
  const title = titleFromPath(targetPath);
  return {
    targetPath,
    targetField: fieldForTarget(targetPath),
    title: `Send to ${title}`,
    description: `Use this result as a starting value in the ${title}.`,
  };
}

function fieldForTarget(path: string) {
  if (/budget/.test(path)) return "monthly";
  if (/debt|credit|repayment/.test(path)) return "payment";
  if (/salary|income|pay/.test(path)) return "income";
  if (/retirement|401k|ira|savings|investment|compound|future-value|present-value|annuity|cd|bond|mutual-fund/.test(path)) return "savings";
  if (/mortgage|loan|lease|refinance|heloc|home-equity|down-payment|affordability/.test(path)) return "amount";
  if (/roi|irr|payback|margin|break-even|depreciation|discount|percent-off|sales-tax|vat|currency|apr|interest-rate/.test(path)) return "amount";
  return "amount";
}

