function readStoredChain(): ChainPayload | null {
  try {
    const parsed = JSON.parse(localStorage.getItem(STORAGE_KEY) || "");
    if (parsed?.createdAt && Date.now() - parsed.createdAt < 1000 * 60 * 60 * 24) return parsed;
  } catch {
    // Ignore malformed localStorage data.
  }
  return null;
}

function writeStoredChain(payload: ChainPayload) {
  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(payload));
  } catch {
    // Ignore private-mode/localStorage failures.
  }
}

function isVisible(element: Element) {
  const el = element as HTMLElement;
  return Boolean(el.offsetParent || el.getClientRects().length);
}

function extractPrimaryNumber() {
  const main = document.querySelector("main") || document.body;
  const nodes = Array.from(main.querySelectorAll<HTMLElement>('[data-testid^="result-"], .bg-gradient-to-br p'))
    .filter((element) => {
      if (!isVisible(element)) return false;
      if (element.closest("[data-calculator-chaining], [data-amortization-visualizer], [data-calculation-history-root]")) return false;
      return true;
    })
    .map((element) => element.textContent?.replace(/\s+/g, " ").trim() || "");

  for (const text of nodes) {
    const match = text.match(/-?\$?\s*[\d,]+(?:\.\d+)?/);
    if (!match) continue;
    const value = Number(match[0].replace(/[$,\s]/g, ""));
    if (Number.isFinite(value)) return value;
  }

  return null;
}

function suggestionsFor(pathname: string): ChainSuggestion[] {
  const explicit = EXPLICIT_CHAINS[pathname];
  if (explicit) return explicit.filter((targetPath) => calculatorPaths.has(targetPath)).map(sendTo);

  if (/tdee|bmr|calorie|macro|protein|carbohydrate|fat-intake/.test(pathname)) {
    return [
      { targetPath: "/calorie-calculator", targetField: "calorie", title: "Use in Calorie Calculator", description: "Carry this energy target into calorie planning." },
      { targetPath: "/macro-calculator", targetField: "calorie", title: "Use in Macro Calculator", description: "Turn this calorie result into protein, carb, and fat targets." },
    ];
  }

  if (/mortgage|rent|housing|real-estate|down-payment|home-equity|heloc|refinance/.test(pathname)) {
    return [
      { targetPath: "/budget-calculator", targetField: "housing", title: "Send to Budget Calculator", description: "Use this monthly housing cost as your budget housing input." },
      { targetPath: "/house-affordability-calculator", targetField: "monthly", title: "Use for Affordability", description: "Compare this payment against income and debt limits." },
    ];
  }

  if (/loan|payment|repayment|debt|credit-card|lease|auto-loan|boat-loan/.test(pathname)) {
    return [
      { targetPath: "/budget-calculator", targetField: "debt payments", title: "Send to Budget Calculator", description: "Use this payment as a monthly debt payment." },
      { targetPath: "/debt-payoff-calculator", targetField: "monthly payment", title: "Use in Debt Payoff", description: "Continue planning payoff time from this payment." },
    ];
  }

  if (/salary|income|paycheck|commission|freelance|hourly/.test(pathname)) {
    return [
      { targetPath: "/budget-calculator", targetField: "monthly income", title: "Send to Budget Calculator", description: "Use this income result to start a monthly budget." },
      { targetPath: "/take-home-pay-calculator", targetField: "salary", title: "Use in Paycheck Calculator", description: "Estimate after-tax take-home pay from this income." },
    ];
  }

  if (/roi|irr|investment|savings|future-value|present-value|retirement|401k|ira/.test(pathname)) {
    return [
      { targetPath: "/investment-calculator", targetField: "initial investment", title: "Use in Investment Calculator", description: "Continue this amount into a growth projection." },
      { targetPath: "/retirement-calculator", targetField: "current savings", title: "Use in Retirement Calculator", description: "Use the result as current retirement savings." },
    ];
  }

  return [];
}

function labelForField(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement) {
  const id = field.id ? CSS.escape(field.id) : "";
  const label =
    (id ? document.querySelector(`label[for="${id}"]`)?.textContent : "") ||
    (id ? document.querySelector(`label[for="${id}-slider"]`)?.textContent : "") ||
    field.closest("label")?.textContent ||
    field.parentElement?.querySelector("label")?.textContent ||
    field.getAttribute("aria-label") ||
    field.getAttribute("placeholder") ||
    field.name ||
    field.id ||
    "";
  return normalize(label);
}

function setNativeValue(field: HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement, value: string) {
  const prototype =
    field instanceof HTMLTextAreaElement ? HTMLTextAreaElement.prototype :
    field instanceof HTMLSelectElement ? HTMLSelectElement.prototype :
    HTMLInputElement.prototype;
  const descriptor = Object.getOwnPropertyDescriptor(prototype, "value");
  descriptor?.set?.call(field, value);
  field.dispatchEvent(new Event("input", { bubbles: true }));
  field.dispatchEvent(new Event("change", { bubbles: true }));
}

function applyChain(payload: ChainPayload) {
  const fields = Array.from(document.querySelectorAll("main input, main select, main textarea"))
    .filter((field): field is HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement =>
      field instanceof HTMLInputElement || field instanceof HTMLSelectElement || field instanceof HTMLTextAreaElement,
    )
    .filter((field) => {
      if (!isVisible(field)) return false;
      if (field.closest("[data-calculator-chaining], [data-amortization-visualizer], [data-calculation-history-root]")) return false;
      if (field instanceof HTMLInputElement && ["hidden", "file", "search", "button", "submit", "reset", "radio", "checkbox", "range"].includes(field.type)) return false;
      return true;
    });

  const wanted = normalize(payload.targetField);
  const field = fields.find((item) => labelForField(item).includes(wanted)) ||
    fields.find((item) => /amount|payment|income|salary|savings|calorie|housing|debt|cost/.test(labelForField(item)));

  if (!field) return false;
  setNativeValue(field, String(Math.round(payload.value * 100) / 100));
  return true;
}

export default function CalculatorChaining() {
  const [location] = useLocation();
  const [resultValue, setResultValue] = useState<number | null>(null);
  const [applied, setApplied] = useState<ChainPayload | null>(null);
  const isCalculator = calculatorPaths.has(location);
  const suggestions = useMemo(() => suggestionsFor(location), [location]);

  useEffect(() => {
    if (!isCalculator) return;
    const refresh = () => setResultValue(extractPrimaryNumber());
    const timers = [250, 800, 1400].map((delay) => window.setTimeout(refresh, delay));
    const onInput = () => window.setTimeout(refresh, 120);
    document.addEventListener("input", onInput);
    document.addEventListener("change", onInput);
    refresh();

    return () => {
      timers.forEach((timer) => window.clearTimeout(timer));
      document.removeEventListener("input", onInput);
      document.removeEventListener("change", onInput);
    };
  }, [isCalculator, location]);

  useEffect(() => {
    if (!isCalculator) return;
    const params = new URLSearchParams(window.location.search);
    const hasChainIntent = params.get("chain") === "1";
    const payload = readStoredChain();
    if (!payload || payload.targetPath !== location || !hasChainIntent) return;

    const timers = [300, 900, 1500].map((delay) =>
      window.setTimeout(() => {
        if (applyChain(payload)) setApplied(payload);
      }, delay),
    );

    return () => timers.forEach((timer) => window.clearTimeout(timer));
  }, [isCalculator, location]);

  if (!isCalculator) return null;

  const hasExplicitSuggestions = Boolean(EXPLICIT_CHAINS[location]);
  const canSuggest = suggestions.length > 0 && (resultValue !== null || hasExplicitSuggestions);
  if (!canSuggest && !applied) return null;

  return (
    <section data-calculator-chaining className="mx-auto max-w-3xl px-4 sm:px-6 py-6">
      <div className="rounded-2xl border border-border bg-card p-5 shadow-sm sm:p-6">
        <div className="mb-4 inline-flex items-center gap-2 rounded-full bg-emerald-500/10 px-3 py-1 text-xs font-bold uppercase tracking-widest text-emerald-600 dark:text-emerald-400">
          <ArrowRightLeft className="h-3.5 w-3.5" />
          Calculator Chaining
        </div>

        {applied && (
          <div className="mb-4 rounded-xl border border-emerald-500/20 bg-emerald-500/10 p-3 text-sm">
            <p className="font-bold text-emerald-700 dark:text-emerald-300">Imported from {applied.sourceName}</p>
            <p className="text-muted-foreground">Applied {applied.label} as {applied.targetField}. You can adjust it before calculating.</p>
          </div>
        )}

        {canSuggest && (
          <>
            <h2 className="text-xl font-extrabold text-foreground">Continue this calculation in another tool</h2>
            <p className="mt-2 text-sm leading-relaxed text-muted-foreground">
              Send this result into a related calculator so the next step starts filled in automatically.
            </p>
            <div className="mt-4 grid grid-cols-1 gap-3 sm:grid-cols-2">
              {suggestions.map((suggestion) => {
                const canPassValue = resultValue !== null;
                const payload: ChainPayload = {
                  sourcePath: location,
                  sourceName: pageName(),
                  targetPath: suggestion.targetPath,
                  targetField: suggestion.targetField,
                  value: resultValue ?? 0,
                  label: resultValue?.toLocaleString(undefined, { maximumFractionDigits: 2 }) || "",
                  createdAt: Date.now(),
                };
                const href = canPassValue ? `${suggestion.targetPath}?chain=1` : suggestion.targetPath;
                return (
                  <a
                    key={`${suggestion.targetPath}-${suggestion.targetField}`}
                    href={href}
                    onClick={canPassValue ? () => writeStoredChain(payload) : undefined}
                    className="group rounded-xl border border-border bg-background p-4 transition-colors hover:border-primary/40 hover:bg-primary/5"
                  >
                    <div className="flex items-start gap-3">
                      <span className="rounded-lg bg-primary/10 p-2 text-primary"><Sparkles className="h-4 w-4" /></span>
                      <span>
                        <span className="block font-extrabold text-foreground">{suggestion.title}</span>
                        <span className="mt-1 block text-sm text-muted-foreground">{suggestion.description}</span>
                        <span className="mt-2 block text-xs font-bold uppercase tracking-widest text-primary">Open {titleFromPath(suggestion.targetPath)}</span>
                      </span>
                    </div>
                  </a>
                );
              })}
            </div>
          </>
        )}
      </div>
    </section>
  );
}
